# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
from functools import wraps
import os
import time
from datetime import datetime

app = Flask(__name__)

ES_HOST = os.environ.get('ELASTICSEARCH_HOST', 'localhost')
ES_PORT = os.environ.get('ELASTICSEARCH_PORT', 9200)
ES_INDEX = os.environ.get('ELASTICSEARCH_INDEX', 'products')

es = Elasticsearch([{'host': ES_HOST, 'port': ES_PORT, 'scheme': 'http'}])

def rate_limit(max_requests=100, window_seconds=60):
    requests_dict = {}
    
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            client_ip = request.remote_addr
            current_time = time.time()
            
            if client_ip not in requests_dict:
                requests_dict[client_ip] = []
            
            requests_dict[client_ip] = [
                req_time for req_time in requests_dict[client_ip]
                if current_time - req_time < window_seconds
            ]
            
            if len(requests_dict[client_ip]) >= max_requests:
                return jsonify({
                    'error': 'Rate limit exceeded',
                    'message': f'Maximum {max_requests} requests per {window_seconds} seconds'
                }), 429
            
            requests_dict[client_ip].append(current_time)
            return f(*args, **kwargs)
        return wrapped
    return decorator

@app.route('/api/search', methods=['GET'])
@rate_limit(max_requests=1000, window_seconds=60)
def search_products():
    query = request.args.get('q', '').strip()
    page = request.args.get('page', 1, type=int)
    page_size = request.args.get('size', 20, type=int)
    
    if not query:
        return jsonify({
            'error': 'Missing query parameter',
            'message': 'Please provide a search keyword using the "q" parameter'
        }), 400
    
    if page < 1:
        page = 1
    
    if page_size < 1 or page_size > 100:
        page_size = 20
    
    from_index = (page - 1) * page_size
    
    try:
        search_body = {
            'query': {
                'multi_match': {
                    'query': query,
                    'fields': ['name^3', 'description^2', 'category', 'brand', 'tags'],
                    'type': 'best_fields',
                    'fuzziness': 'AUTO'
                }
            },
            'from': from_index,
            'size': page_size,
            'sort': [
                {'_score': {'order': 'desc'}},
                {'popularity': {'order': 'desc'}}
            ],
            'highlight': {
                'fields': {
                    'name': {},
                    'description': {}
                },
                'pre_tags': ['<em>'],
                'post_tags': ['</em>']
            }
        }
        
        response = es.search(index=ES_INDEX, body=search_body)
        
        hits = response['hits']
        total = hits['total']['value'] if isinstance(hits['total'], dict) else hits['total']
        
        products = []
        for hit in hits['hits']:
            product = hit['_source']
            product['id'] = hit['_id']
            product['score'] = hit['_score']
            
            if 'highlight' in hit:
                product['highlight'] = hit['highlight']
            
            products.append(product)
        
        total_pages = (total + page_size - 1) // page_size
        
        return jsonify({
            'success': True,
            'query': query,
            'total': total,
            'page': page,
            'page_size': page_size,
            'total_pages': total_pages,
            'products': products,
            'took': response['took']
        }), 200
        
    except Exception as e:
        app.logger.error(f'Elasticsearch error: {str(e)}')
        return jsonify({
            'error': 'Search failed',
            'message': 'An error occurred while processing your search request'
        }), 500

@app.route('/health', methods=['GET'])
def health_check():
    try:
        es_health = es.cluster.health()
        return jsonify({
            'status': 'healthy',
            'elasticsearch': {
                'connected': True,
                'cluster_status': es_health['status']
            },
            'timestamp': datetime.utcnow().isoformat()
        }), 200
    except Exception as e:
        return jsonify({
            'status': 'unhealthy',
            'elasticsearch': {
                'connected': False,
                'error': str(e)
            },
            'timestamp': datetime.utcnow().isoformat()
        }), 503

@app.errorhandler(404)
def not_found(error):
    return jsonify({'error': 'Not found'}), 404

@app.errorhandler(500)
def internal_error(error):
    return jsonify({'error': 'Internal server error'}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, threaded=True)